// Extrair texto do payload recebido do 020
const inputData = $input.all()[0].json;
const textoOriginal = inputData.post_texto || inputData.texto || "Nenhum texto recebido";

// Regras pesadas de Compliance:
const shadowban_words = ["compre", "venda", "preço", "orçamento", "clique no link", "arraste para cima", "promoção", "desconto", "urgente", "oferta"];

let textoLimpo = textoOriginal;
let hasSpam = false;

shadowban_words.forEach(word => {
  const regex = new RegExp(word, "gi");
  if (regex.test(textoLimpo)) {
    hasSpam = true;
    textoLimpo = textoLimpo.replace(regex, "[termo orgânico ajustado]"); 
    // OBS: Num cenário avencado, poderiamos chamar a IA aqui para reescrever de forma fluida.
  }
});

let target_channels = inputData.target_channels || ["facebook", "instagram", "tiktok"];
const formatoMidia = inputData.formato || "imagem";

// O TikTok bloqueia imagens estaticas
if (formatoMidia !== "video" && target_channels.includes("tiktok")) {
  target_channels = target_channels.filter(c => c !== "tiktok");
}

return {
  json: {
    texto_original: textoOriginal,
    texto_compliance: textoLimpo,
    shadowban_risk_detected: hasSpam,
    formato_recebido: formatoMidia,
    canais_aprovados: target_channels
  }
};
